import{_ as s,o as a,c as t,ai as n}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"Electron App Overview","description":"Prism Electron desktop app — a standalone IDE-independent application sharing core business logic with the VS Code extension.","frontmatter":{"title":"Electron App Overview","description":"Prism Electron desktop app — a standalone IDE-independent application sharing core business logic with the VS Code extension.","outline":[2,3]},"headers":[],"relativePath":"electron/index.md","filePath":"electron/index.md","lastUpdated":0}'),i={name:"electron/index.md"};function r(o,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="electron-app-overview" tabindex="-1">Electron App Overview <a class="header-anchor" href="#electron-app-overview" aria-label="Permalink to “Electron App Overview”">​</a></h1><p>The Prism Electron app is a standalone desktop application that runs the same React UI and business logic as the VS Code extension, but independent of any IDE. It uses Electron&#39;s IPC model as the transport layer instead of VS Code&#39;s <code>postMessage</code>, and replaces all VS Code API dependencies with pure Node.js equivalents.</p><p>The Electron app was built by wiring the existing platform-agnostic prism-vscode core + React UI into Electron&#39;s IPC model, then replacing the 8 VS Code-coupled files with Electron equivalents.</p><h2 id="what-s-shared-from-prism-vscode" tabindex="-1">What&#39;s Shared (from prism-vscode) <a class="header-anchor" href="#what-s-shared-from-prism-vscode" aria-label="Permalink to “What&#39;s Shared (from prism-vscode)”">​</a></h2><ul><li>All business logic: workflow state machine, spectrum engine, stories manager, signal parser</li><li>All Claude CLI integration: runner, parser, events</li><li>All React UI components: ChatView, SpectrumView, WelcomeView, and all sub-components</li><li>The complete gRPC-over-postMessage protocol (unchanged)</li><li>Service clients: StateService, ChatService, WorkflowService, PluginService, SpectrumService</li></ul><h2 id="what-differs-platform-shell" tabindex="-1">What Differs (platform shell) <a class="header-anchor" href="#what-differs-platform-shell" aria-label="Permalink to “What Differs (platform shell)”">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>VS Code</th><th>Electron</th></tr></thead><tbody><tr><td>IPC transport</td><td><code>webview.postMessage</code> / <code>onDidReceiveMessage</code></td><td><code>ipcMain.handle()</code> / <code>ipcRenderer.invoke()</code></td></tr><tr><td>Workspace detection</td><td><code>vscode.workspace.workspaceFolders</code></td><td><code>dialog.showOpenDialog</code> + stored project dir</td></tr><tr><td>File watching</td><td><code>vscode.FileSystemWatcher</code></td><td><code>chokidar</code></td></tr><tr><td>File I/O</td><td><code>vscode.workspace.fs.stat()</code></td><td>Node.js <code>fs/promises</code></td></tr><tr><td>Config storage</td><td>VS Code settings API</td><td>Plain JSON file in <code>app.getPath(&#39;userData&#39;)</code></td></tr><tr><td>Event system</td><td><code>vscode.EventEmitter</code></td><td>Node.js <code>EventEmitter</code></td></tr><tr><td>Context keys</td><td><code>vscode.commands.executeCommand(&#39;setContext&#39;, ...)</code></td><td>Not applicable (no-op)</td></tr></tbody></table><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to “Key Features”">​</a></h2><ul><li>Full Prism chat interface with streaming Claude CLI responses</li><li>Spectrum autonomous execution dashboard with real-time story updates</li><li>Native OS menu bar (File → Open Project, standard Edit/View/Window)</li><li>Window state persistence (bounds, last project directory)</li><li>CLI argument support: <code>prism-electron /path/to/project</code></li><li>Context-isolated renderer with Electron Fuses security hardening</li><li>Distributable installers via Electron Forge (Squirrel Windows, ZIP macOS, deb/rpm Linux)</li></ul><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to “Technology Stack”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Prism Electron v1.0.0                            │</span></span>
<span class="line"><span>├──────────────┬──────────────┬──────────────┬────────────────────────┤</span></span>
<span class="line"><span>│  Electron 40 │ React 18.3.1 │   Vite 6.0   │   Tailwind CSS 4.2    │</span></span>
<span class="line"><span>│  (Chromium)  │   (UI)       │   (Build)    │   (Styling)           │</span></span>
<span class="line"><span>├──────────────┴──────────────┴──────────────┴────────────────────────┤</span></span>
<span class="line"><span>│  @prism-core/* — Shared business logic from packages/prism-core    │</span></span>
<span class="line"><span>│  @prism-ui/*  — Shared React components from packages/prism-ui     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  chokidar (file watching) │ uuid (request IDs) │ electron-forge     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  TypeScript 5.4.5 │ ESLint │ Prettier                              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><blockquote><p><strong>Note</strong>: The root <code>package.json</code> declares React 19, but <code>webview-ui/package.json</code> pins React 18.3.1.</p></blockquote>`,12)])])}const u=s(i,[["render",r]]);export{m as __pageData,u as default};
